parameters.jsCode:
// Code Node in n8n
// Erwartet: item.json.choices[0].message.content = JSON-String (vom OpenAI-Node)
// Liefert: für jedes Item ein geparstes JSON-Objekt, in dem alle "\n" in Strings durch " " ersetzt wurden

function replaceNewlinesInStrings(value) {
  if (typeof value === 'string') {
    // alle echten Zeilenumbrüche durch Leerzeichen ersetzen
    return value.replace(/\n/g, ' ');
  }

  if (Array.isArray(value)) {
    return value.map(replaceNewlinesInStrings);
  }

  if (value !== null && typeof value === 'object') {
    const out = {};
    for (const key of Object.keys(value)) {
      out[key] = replaceNewlinesInStrings(value[key]);
    }
    return out;
  }

  // Zahlen, Booleans, null, etc. unverändert zurückgeben
  return value;
}

function parseContentToJson(raw) {
  if (!raw || typeof raw !== 'string') {
    throw new Error('No valid content to parse');
  }

  let text = raw.trim();

  // Optional: Codefences entfernen, falls das Modell ```json ... ``` zurückgibt
  if (text.startsWith('```')) {
    text = text.replace(/^```[a-zA-Z]*\s*/, '').replace(/```$/, '').trim();
  }

  const parsed = JSON.parse(text);

  // alle "\n" in Strings innerhalb des Objekts ersetzen
  return replaceNewlinesInStrings(parsed);
}

// Alle Items verarbeiten
const out = items.map((item) => {
  const raw = item.json.choices[0].message.content; // Pfad ggf. anpassen
  const parsed = parseContentToJson(raw);

  // Nur das geparste JSON weitergeben
  /*
  return {
    json: parsed,
  };
  */
  // Wenn du zusätzlich Originaldaten behalten willst:

  return {
    json: {
      ...$('Webhook1').first().json.body,
      ...parsed,
    },
  };

});

return out;

